svg.script:
    const lines = [
      "CS Student📍Hong Kong",
      "Exploring Robotics and AI Systems",
      "Piling up the stack and developing!",
      "Always Learning"
    ];

    const textElement = document.getElementById("line");

    let lineIndex = 0;
    let charIndex = 0;
    let currentText = "";
    let deleting = false;

    function type() {
      const fullText = lines[lineIndex];

      if (!deleting) {
        currentText = fullText.substring(0, charIndex++);
      } else {
        currentText = fullText.substring(0, charIndex--);
      }

      textElement.textContent = currentText;

      let speed = deleting ? 40 : 70;

      if (!deleting && charIndex === fullText.length) {
        speed = 1400;
        deleting = true;
      } else if (deleting && charIndex === 0) {
        deleting = false;
        lineIndex = (lineIndex + 1) % lines.length;
        speed = 500;
      }

      setTimeout(type, speed);
    }

    type();
